          </FlexBox>
        );
      }
      if (row.id === '2') {
        return null;
      }
      return (
        <FlexBox
          style={{ backgroundColor: 'lightgrey', height: '50px' }}
          justifyContent={FlexBoxJustifyContent.Center}
          alignItems={FlexBoxAlignItems.Center}
          direction={FlexBoxDirection.Column}
        >
          <Tag>height: 50px</Tag>
          <Text>This subcomponent will be displayed below all rows except the first, second and third.</Text>
        </FlexBox>
      );
    };
    return context.viewMode === 'story' ? (
      <AnalyticalTable {...args} renderRowSubComponent={renderRowSubComponent} />
    ) : (
      <ToggleableTable {...args} renderRowSubComponent={renderRowSubComponent} />
    );
  },
};

export const DynamicRowCount = {
  args: { visibleRowCountMode: AnalyticalTableVisibleRowCountMode.Auto, containerHeight: 250 } as unknown,
  argTypes: {
    containerHeight: {
      options: [250, 500, 750, 1000],
      control: {
        type: 'radio',
      },
      description:
        'Select an option to change the height of the surrounding container of the table (in `px`). <br /> __Note__: This is not an actual prop of the table.',
    },
  },
  render: (args, context) => {
    const [data, setData] = useState(args.data);
    const handleClick = () => {
      setData((prev) => {
        if (prev.length > 4) {
          return args.data.slice(0, 4);
        } else {
          return args.data;
        }
      });
    };
    return (
      <>
        <Button onClick={handleClick}>Toggle Number of Rows</Button>
        <br />
        <Text>Number of visible rows: {data.length}</Text>
        <hr />
        <div style={{ height: `${args.containerHeight}px` }}>
          {context.viewMode === 'story' ? (
            <AnalyticalTable
              {...args}
              data={data}
              visibleRowCountMode={args.visibleRowCountMode}
              header={`Current height: ${args.containerHeight}px - Change the height in the table above`}
            />
          ) : (
            <ToggleableTable
              {...args}
              data={data}
              visibleRowCountMode={args.visibleRowCountMode}
              header={`Current height: ${args.containerHeight}px - Change the height in the table above`}
            />
          )}
        </div>
      </>
    );
  },
};

export const ResponsiveColumns: Story = {
  args: {
    visibleRowCountMode: AnalyticalTableVisibleRowCountMode.Fixed,
    // @ts-expect-error: custom prop for the controls table
    containerWidth: 'auto',
    data: dataLarge,
    adjustTableHeightOnPopIn: true,
    columns: [
      {
        Header: 'Name',
        accessor: 'name',
      },
      {
        disableSortBy: true,
        responsivePopIn: true,
        responsiveMinWidth: 601,
        PopInHeader: 'Custom Header Text (age)',
        Header: 'Age',
        accessor: 'age',
      },
      {
        disableSortBy: true,
        responsivePopIn: true,
        responsiveMinWidth: 401,
        Header: 'Friend Name',
        PopInHeader: (instance) => {
          return <div style={{ color: 'red' }}>Friend Name (custom)</div>;
        },
        accessor: 'friend.name',
      },
      { disableSortBy: true, responsiveMinWidth: 401, Header: 'Friend Age', accessor: 'friend.age' },
      {
        disableSortBy: true,
        responsivePopIn: true,
        responsiveMinWidth: 801,
        id: 'actions',
        Header: 'Actions',
        width: 100,
        disableResizing: true,
        Cell: (instance) => {
          return (
            <FlexBox>
              <Button icon="edit" />
              <Button icon="delete" />
            </FlexBox>
          );
        },
      },
      {
        id: 'popinDisplay',
        Header: 'PopinDisplay Modes',
        responsivePopIn: true,
        responsiveMinWidth: 801,
        popinDisplay: AnalyticalTablePopinDisplay.Block,
        Cell: () => {
          return <Text maxLines={1}>Using popinDisplay: 'Block'</Text>;
        },
      },
    ],
  },
  argTypes: {
    // @ts-expect-error: custom prop for the controls table
    containerWidth: {
      options: [400, 600, 800, 'auto'],
      control: {
        type: 'radio',
      },
      description:
        'Select an option to change the width of the surrounding container of the table (in `px`). <br /> __Note__: This is not a prop of the table.',
    },
  },
  render: (args, context) => {
    const [columns, setColumns] = useState(args.columns);
    const [popinDisplay, setPopinDisplay] = useState<AnalyticalTableColumnDefinition['popinDisplay']>(
      AnalyticalTablePopinDisplay.Block,
    );
    const { containerWidth: _0, ...tableArgs } = args;

    useEffect(() => {
      setColumns((prev) => {
        return [
          ...prev.slice(0, -1),
          {
            id: 'popinDisplay',
            Header: 'PopinDisplay Modes',
            responsivePopIn: true,
            responsiveMinWidth: 801,
            popinDisplay: popinDisplay,
            Cell: () => {
              return <Text maxLines={1}>Using popinDisplay: {popinDisplay}</Text>;
            },
          },
        ];
      });
    }, [popinDisplay]);

    return (
      <div
        style={{
          width: args.containerWidth && typeof args.containerWidth === 'number' ? `${args.containerWidth}px` : 'auto',
        }}
      >
        <Label showColon style={{ marginInlineEnd: '0.5rem' }}>
          Change <code>popinDisplay</code> of last column
        </Label>
        <Select
          onChange={(e) => {
            setPopinDisplay(e.detail.selectedOption.textContent as AnalyticalTableColumnDefinition['popinDisplay']);
          }}
        >
          <Option selected={popinDisplay === AnalyticalTablePopinDisplay.Block}>Block</Option>
          <Option selected={popinDisplay === AnalyticalTablePopinDisplay.Inline}>Inline</Option>
          <Option selected={popinDisplay === AnalyticalTablePopinDisplay.WithoutHeader}>WithoutHeader</Option>
        </Select>
        {context.viewMode === 'story' ? (
          <AnalyticalTable
            {...tableArgs}
            columns={columns}
            adjustTableHeightOnPopIn={args.adjustTableHeightOnPopIn}
            header={`Current width: ${args.containerWidth}`}
          />
        ) : (
          <>
            <hr />
            <ToggleableTable
              {...tableArgs}
              columns={columns}
              adjustTableHeightOnPopIn={args.adjustTableHeightOnPopIn}
              header={`Current width: ${args.containerWidth}`}
            />
          </>
        )}
      </div>
    );
  },
};

export const NavigationIndicator: Story = {
  args: { withNavigationHighlight: true, selectionMode: AnalyticalTableSelectionMode.Multiple, data: dataLarge },
  render: (args, context) => {
    const [selectedRow, setSelectedRow] = useState();
    const onRowSelect = (e) => {
      setSelectedRow(e.detail.row);
    };
    const markNavigatedRow = useCallback(
      (row) => {
        return selectedRow?.id === row.id;
      },
      [selectedRow],
    );
    return context.viewMode === 'story' ? (
      <AnalyticalTable {...args} markNavigatedRow={markNavigatedRow} onRowSelect={onRowSelect} />
    ) : (
      <ToggleableTable {...args} markNavigatedRow={markNavigatedRow} onRowSelect={onRowSelect} />
    );
  },
};

export const CustomFilter: Story = {
  args: {
    data: dataLarge,
    filterable: true,
  },
  render: (args, context) => {
    const filterFn = useCallback((rows, accessor, filterValue) => {
      if (filterValue.length > 0) {
        return rows.filter((row) => {
          const rowVal = row.values[accessor];
          return !!filterValue.some((item) => rowVal.includes(item));
        });
      }
      return rows;
    }, []);
    const columns: AnalyticalTableColumnDefinition[] = useMemo(
      () => [
        {
          Header: 'Custom Column Filter',
          accessor: 'name',
          filter: filterFn,
          Filter: ({ column }) => {
            const firstNames = ['Carl', 'Dan', 'Rose', 'Susanne'];
            return (
              <MultiComboBox
                placeholder="Filter Names"
                onSelectionChange={(e) => {
                  column.setFilter(e.detail.items.map((item) => item.getAttribute('text')));
                }}
              >
                {firstNames.map((item) => {
                  const isSelected = column?.filterValue?.some((filterVal) => filterVal.includes(item));
                  return <MultiComboBoxItem text={item} key={item} selected={isSelected} />;
                })}
              </MultiComboBox>
            );
          },
        },
        {
          Header: 'Age',
          accessor: 'age',
        },
      ],
      [],
    );
    return context.viewMode === 'story' ? (
      <AnalyticalTable {...args} columns={columns} />
    ) : (
      <ToggleableTable {...args} columns={columns} />
    );
  },
};

export const NoData: Story = {
  render(args, context) {
    const [selected, setSelected] = useState('noData');
    const [filtered, setFiltered] = useState(false);
    const handleChange: SegmentedButtonPropTypes['onSelectionChange'] = (e) => {
      const { key } = e.detail.selectedItems[0].dataset;
      setSelected(key);
      if (key === 'data') {
        setFiltered(false);
      }
    };
    const handleClick: ToggleButtonPropTypes['onClick'] = (e) => {
      setFiltered(!!e.target.pressed);
    };

    const NoDataComponent: AnalyticalTablePropTypes['NoDataComponent'] =
      selected === 'noData'
        ? undefined
        : (props) => {
            return filtered ? (
              <IllustratedMessage role={props.accessibleRole} name={NoFilterResults} />
            ) : (
              <IllustratedMessage role={props.accessibleRole} name={NoDataIllustration} />
            );
          };

    const tableProps = {
      ...args,
      data: selected === 'data' ? args.data : [],
      globalFilterValue: filtered ? 'Non-existing text' : undefined,
      NoDataComponent: NoDataComponent,
    };

    const isAutoRowCount = args.visibleRowCountMode?.startsWith('Auto');

    return (
      <>
        <SegmentedButton onSelectionChange={handleChange} accessibleName="Select data view mode">
          <SegmentedButtonItem selected={selected === 'noData'} data-key="noData">
            Default NoData Component
          </SegmentedButtonItem>
          <SegmentedButtonItem selected={selected === 'illustratedMessage'} data-key="illustratedMessage">
            IllustratedMessage NoData Component
          </SegmentedButtonItem>
          <SegmentedButtonItem selected={selected === 'data'} data-key="data">
            With Data
          </SegmentedButtonItem>
        </SegmentedButton>{' '}
        |{' '}
        <ToggleButton onClick={handleClick} pressed={filtered} disabled={selected === 'data'}>
          Table filtered
        </ToggleButton>
        {context.viewMode === 'story' ? (
          <div style={{ height: isAutoRowCount ? '300px' : 'auto' }}>
            <AnalyticalTable {...tableProps} />
          </div>
        ) : (
          <>
            <hr />
            <div style={{ height: isAutoRowCount ? '300px' : 'auto' }}>
              <ToggleableTable {...tableProps} />
            </div>
          </>
        )}
      </>
    );
  },
};

export const KitchenSink: Story = {
  args: kitchenSinkArgs,
  render(args, context) {
    return context.viewMode === 'story' ? <AnalyticalTable {...args} /> : <ToggleableTable {...args} />;
  },
};

// ===================== Not displayed in sidebar & tags popover =====================

export const EllipsisExamples: Story = {
  tags: ['excludeFromSidebar'],
  args: {
    data: dataLarge.slice(0, 5),
    columns: [
      {
        Header: 'Plain String (Automatic Ellipsis)',
        accessor: 'name',
        width: 60,
        Cell: ({ value }) => value,
      },
      {
        Header: 'With textEllipsis Class',
        accessor: 'friend.name',
        width: 60,
        Cell: ({ value, webComponentsReactProperties }) => (
          <div className={webComponentsReactProperties.classes.textEllipsis} title={value}>
            {value}
          </div>
        ),
      },
      {
        Header: 'With Text Component',
        id: 'description',
        width: 60,
        Cell: () => (
          <Text maxLines={1} title="This is a very long text that demonstrates how the Text component handles ellipsis">
            This is a very long text that demonstrates how the Text component handles ellipsis
          </Text>
        ),
      },
    ],
    visibleRows: 5,
    style: { width: 'min(100%, 300px)' },
  },
};

data-display-analyticaltable--docs.content:
import { ControlsWithNote, DocsHeader, Footer } from '@sb/components';
import { Canvas, Meta } from '@storybook/addon-docs/blocks';
import * as ComponentStories from './AnalyticalTable.stories';

<Meta of={ComponentStories} />

<DocsHeader of={ComponentStories} />

<br />

## Example

<Canvas of={ComponentStories.Default} />

### Code

<details>

<summary>Show shortened Code</summary>

```jsx
const columns = [
  {
    Header: 'Name',
    accessor: 'name'
  },
  {
    Header: 'Age',
    accessor: 'age'
  },
  {
    Header: 'Friend Name',
    accessor: 'friend.name'
  },
  {
    Header: 'Friend Age',
    accessor: 'friend.age'
  }
];

const data = [
  {
    age: 80,
    friend: {
      age: 68,
      name: 'Carver Vance'
    },
    name: 'Allen Best',
    status: 'Positive'
  },
  {
    age: 31,
    friend: {
      age: 70,
      name: 'Strickland Gallegos'
    },
    name: 'Combs Fleming',
    status: 'None'
  }
  // shortened for readability
];

const TableComp = () => {
  return (
    <AnalyticalTable
      columns={columns}
      data={data}
      visibleRows={5}
      onAutoResize={() => {}}
      onColumnsReorder={() => {}}
      onGroup={() => {}}
      onLoadMore={() => {}}
      onRowClick={() => {}}
      onRowExpandChange={() => {}}
      onRowSelect={() => {}}
      onSort={() => {}}
      onTableScroll={() => {}}
    />
  );
};
```

</details>

## Properties

<ControlsWithNote of={ComponentStories.Default} />

## Column Properties

**Required Attributes**

| Attribute  | Type                                                                                                                                                      | Description                                                                                                                                                                                                                    |
| ---------- | --------------------------------------------------------------------------------------------------------------------------------------------------------- | ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------ |
| `accessor` | `string` OR <br />`(originalRow: Record<string, any>, rowIndex: number, row: RowType,` <br />`parentRows: RowType[], data: Record<string, any>[]) => any` | This `string`/`function` is used to build the data model for your column.<br /><br />**Note**: You can also specify deeply nested values with accessors like `info.hobby` or even `address[0].street`.<br />                   |
| `id`       | `string`                                                                                                                                                  | Defines the unique ID for the column. It is used by reference in things like sorting, grouping, filtering, etc.<br /><br />**Note:** If no `accessor` is set, or the `accessor` is a function, the `id` property is mandatory. |

**Optional Properties**

| Attribute               | Type                                                                                                | Description                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       |
| ----------------------- | --------------------------------------------------------------------------------------------------- | --------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- |
| `Header`                | `string` OR<br/>`ComponentType`                                                                     | Can either be `string` or a React component that will be rendered as column header                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                |
| `headerLabel`           | `string`                                                                                            | Defines the `aria-label` for the whole column read by screen readers.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             |
| `headerTooltip`         | `string`                                                                                            | Tooltip for the column header. If not set, the display text will be the same as the Header if it is a `string`                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    |
| `Cell`                  | `string` OR<br />`ComponentType`<br/>`<CellInstance>`                                               | Custom cell renderer. If set, the table will use this component or render the provided string for every cell, passing all necessary information as props, e.g., the cell value as `props.value`.<br /><br />**Note:**<ul><li>Using a custom component **can impact performance**! If you pass a component, **memoizing it is strongly recommended**, especially for complex components or large datasets.</li><li>For custom elements, text truncation needs to be applied manually. [Here](https://ui5.github.io/webcomponents-react/v2/?path=/docs/data-display-analyticaltable-recipes--docs) you can find out more.</li></ul> |
| `cellLabel`             | `({cell, instance})`<br/>`=> string`                                                                | Defines a function that receives an object as a parameter, including the cell and table instance, and should return the `aria-label` of the current cell. <br /><br />**Note:** Use this property if there is no textual content available through the dataset (e.g. no `accessor` field available), or if you want to provide additional context when navigating to the respective cell for screen readers.<br /><br />**Note:** To retrieve the internal `aria-label`, utilize the `cell.cellLabel` property.                                                                                                                   |
| `width`                 | `number`                                                                                            | Defines the column width. If not set, the table will distribute all columns without a width evenly.<br />**Note:** The `width` cannot be less than `minWidth`. Since `minWidth` defaults to 60, set a lower `minWidth` to allow narrower columns.                                                                                                                                                                                                                                                                                                                                                                                 |
| `minWidth`              | `number`                                                                                            | Minimum width of the column.<br />**Default:** `60`                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               |
| `maxWidth`              | `number`                                                                                            | Maximum width of the column.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      |
| `Filter`                | `ComponentType`                                                                                     | Filter Component to be rendered in the Header                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     |
| `disableFilters`        | `boolean`                                                                                           | Disable filters for this column                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   |
| `disableGlobalFilter`   | `boolean`                                                                                           | Disable global filtering for this column                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          |
| `defaultCanFilter`      | `boolean`                                                                                           | If set to true, this column will be filterable, regardless if it has a valid `accessor`                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           |
| `filter`                | `string OR Function`                                                                                | Either a string or a filter function.<br />Supported String Values: <ul><li>`text`</li><li>`exactText`</li><li>`exactTextCase`</li><li>`equals`</li></ul>**Note:** When the standard `Filter` component is used, the filter function is not triggered if the `filterValue` is empty, as the filter is then removed.                                                                                                                                                                                                                                                                                                               |
| `Aggregated`            | `ComponentType`                                                                                     | Component to render for aggregated cells                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          |
| `aggregate`             | `string` OR<br/>`((leafValues,`<br/>`aggregatedValues)`<br/>`=> any)`                               | Aggregation function or string.<br />Supported String Values: <ul><li>`sum`</li><li>`min`</li><li>`max`</li><li>`minMax`</li><li>`average`</li><li>`median`</li><li>`unique`</li><li>`uniqueCount`</li><li>`count`</li></ul>                                                                                                                                                                                                                                                                                                                                                                                                      |
| `aggregateValue`        | `string` OR<br/>`((values, row,`<br/>`column) => any)`                                              | When attempting to group/aggregate non primitive cell values (eg. arrays of items) you will likely need to resolve a stable primitive value like a number or string to use in normal row aggregations. This property can be used to aggregate or simply access the value to be used in aggregations eg. count-ing the unique number of items in a cell's array value before sum-ing that count across the table                                                                                                                                                                                                                   |
| `disableGroupBy`        | `boolean`                                                                                           | Disable groupBy for this column                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   |
| `defaultCanSort`        | `boolean`                                                                                           | If set to true, this column will be sortable, regardless if it has a valid `accessor`                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             |
| `disableSortBy`         | `boolean`                                                                                           | Disable sorting for this column                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   |
| `sortDescFirst`         | `boolean`                                                                                           | If set to `true`, the first sort direction for this column will be descending instead of ascending.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               |
| `sortInverted`          | `boolean`                                                                                           | If set to `true`, the underlying sorting direction will be inverted, but the UI will not.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         |
| `sortType`              | `string` OR<br/>`((rowA, rowB,`<br/>`columnId: string,`<br/>`descending: boolean)`<br/>`=> number)` | String or custom **memoized** sort function.<br />Supported String Values: <ul><li>`basic`</li><li>`datetime`</li><li>`alphanumeric`</li></ul>**Default:**`'alphanumeric'`                                                                                                                                                                                                                                                                                                                                                                                                                                                        |
| `disableResizing`       | `boolean`                                                                                           | Disable resizing for this column                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  |
| `hAlign`                | `TextAlign`                                                                                         | Horizontal align of the cell                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      |
| `vAlign`                | `VerticalAlign`                                                                                     | Vertical align of the cell                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        |
| `scaleWidthModeOptions` | `ScaleWidthModeOptions`                                                                             | Allows passing a custom string for the internal width calculation of custom cells for `scaleWidthMode` `Grow` and `Smart`. More <a href="./?path=/docs/data-display-analyticaltable-recipes--docs#how-to-scale-custom-cells">here</a>                                                                                                                                                                                                                                                                                                                                                                                             |
| `responsivePopIn`       | `boolean`                                                                                           | Enables the pop-in behavior of the column. When the `responsiveMinWidth` is smaller then the width of the table, the content of each cell will move to the first cell in the row, improving usability on small or mobile devices.<br />**Note:** At least one column must remain visible at all times!                                                                                                                                                                                                                                                                                                                            |
| `responsiveMinWidth`    | `number`                                                                                            | Defines how the table should react when its width falls below the `responsiveMinWidth`. <ul><li>If `responsivePopIn` is `true` the content of this column will be moved to the first column.</li><li>If `responsivePopIn` is not set or `false` the column will be hidden.</li></ul>                                                                                                                                                                                                                                                                                                                                              |
| `PopInHeader`           | `string` OR<br/>`ComponentType`                                                                     | Custom pop-in header renderer. If set, the table will call that component for every column that is "popped-in" and pass the table instance as prop.                                                                                                                                                                                                                                                                                                                                                                                                                                                                               |
| `popinDisplay`          | `AnalyticalTablePopinDisplay`                                                                       | Defines the display of `AnalyticalTable` pop-ins.<br />**Default:** `AnalyticalTablePopinDisplay.Block`                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           |
| `disableDragAndDrop`    | `boolean`                                                                                           | Defines if the column is reorderable by dragging and dropping columns.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            |
| `enableMultiSort`       | `boolean`                                                                                           | Defines whether this column should allow multi-sort.<br /><br /> **Note:** When sorting by a column that does not allow multiple sorting, only the current column is sorted and all other sorted columns are reset.                                                                                                                                                                                                                                                                                                                                                                                                               |
| `autoResizable`         | `boolean`                                                                                           | Defines whether double-clicking a columns resizer will automatically resize the column to fit the largest cell content of visible rows.<br /><br />**Note:** Only default text content is supported by this option, for custom content it might work as well, but we recommend checking the behavior carefully as the logic can't account for all possible implementations.                                                                                                                                                                                                                                                       |

<br />

# More Examples

<br />

## Tree Table

<Canvas of={ComponentStories.TreeTable} sourceState={'none'} />

The `data` structure of the tree table is as follows:

```js
const data = {
    name: "Greg Miller",
    age: 35,
    friend: {
        name: "Rose Franco",
        age: 32,
    },
    status: "None",
    subRows: [
        {
            name: "Rick DeAngelo",
            age: 25,
            friend: {
                name: "Susanne Franco",
                age: 37,
            },
            status: "None",
            subRows: [...],
        },
    ],
    ...
};
```

In this example the default key for sub row detection is used (`subRows`), you can use any key you like by setting the `subRowsKey` prop.

<br />

## Infinite Scrolling

The table initially contains 50 rows, when the last 10 rows are reached the table will load more data.

**Note:** To prevent the table state from resetting when the data is updated, please see [this recipe](?path=/docs/data-display-analyticaltable-recipes--docs#how-to-stop-the-table-state-from-automatically-resetting-when-the-data-changes).

<Canvas sourceState="none" of={ComponentStories.InfiniteScrolling} />

### Code

<details>

<summary>Show Code</summary>

```jsx
const InfiniteScrollTable = (props) => {
  const [data, setData] = useState(props.data.slice(0, 50));
  const [loading, setLoading] = useState(false);
  const offset = useRef(50);
  const onLoadMore = () => {
    setLoading(true);
  };
  useEffect(() => {
    if (loading) {
      setTimeout(() => {
        setData((prev) => [...prev, ...props.data.slice(offset.current, offset.current + 50)]);
        setLoading(false);
        offset.current += 50;
      }, 2000);
    }
  }, [loading, props.data, offset.current]);
  return (
    <AnalyticalTable
      data={data}
      columns={props.columns}
      infiniteScroll={true}
      infiniteScrollThreshold={10}
      header="Scroll to load more data"
      onLoadMore={onLoadMore}
      loading={loading}
      reactTableOptions: {{ autoResetSelectedRows: false }}
    />
  );
};
```

</details>

## AnalyticalTable with subcomponents

Adding custom subcomponents below table rows can be achieved by setting the `renderRowSubComponent` prop.
The prop expects a function with an optional parameter containing the `row` instance, there you can control which row should display subcomponents. If you want to display the subcomponent at the bottom of the row without an expandable container, you can set `subComponentsBehavior` prop to `"Visible"` or to `"IncludeHeight"`. "Visible" simply adds the subcomponent to the row without including its height in the initial calculation of the table body, whereas "IncludeHeight" does.

### Notes

- When `renderRowSubComponent` is set, `grouping` is disabled.
- When rendering active elements inside the subcomponent, make sure to add the `data-subcomponent-active-element' attribute, otherwise focus behavior won't be consistent.
- When `AnalyticalTableSubComponentsBehavior.IncludeHeight` or `AnalyticalTableSubComponentsBehavior.IncludeHeightExpandable` is used, `AnalyticalTableVisibleRowCountMode.Interactive` is not supported.

<ControlsWithNote of={ComponentStories.Subcomponents} include={['renderRowSubComponent', 'subComponentsBehavior']} />

<Canvas sourceState="none" of={ComponentStories.Subcomponents} />

### Code

<details>

<summary>Show Code</summary>

```jsx
const TableWithSubcomponents = (props) => {
  const renderRowSubComponent = (row) => {
    if (row.id === '0') {
      return (
        <FlexBox
          style={{ backgroundColor: 'lightblue', height: '300px' }}
          justifyContent={FlexBoxJustifyContent.Center}
          alignItems={FlexBoxAlignItems.Center}
          direction={FlexBoxDirection.Column}
        >
          <Tag>height: 300px</Tag>
          <Text>This subcomponent will only be displayed below the first row.</Text>
          <hr />
          <Text>
            The button below is rendered with `data-subcomponent-active-element` attribute to ensure consistent focus
            behavior
          </Text>
          <Button data-subcomponent-active-element>Click</Button>
        </FlexBox>
      );
    }
    if (row.id === '1') {
      return (
        <FlexBox
          style={{ backgroundColor: 'lightyellow', height: '100px' }}
          justifyContent={FlexBoxJustifyContent.Center}
          alignItems={FlexBoxAlignItems.Center}
          direction={FlexBoxDirection.Column}
        >
          <Tag>height: 100px</Tag>
          <Text>This subcomponent will only be displayed below the second row.</Text>
        </FlexBox>
      );
    }
    if (row.id === '2') {
      return null;
    }
    return (
      <FlexBox
        style={{ backgroundColor: 'lightgrey', height: '50px' }}
        justifyContent={FlexBoxJustifyContent.Center}
        alignItems={FlexBoxAlignItems.Center}
        direction={FlexBoxDirection.Column}
      >
        <Tag>height: 50px</Tag>
        <Text>This subcomponent will be displayed below all rows except the first, second and third.</Text>
      </FlexBox>
    );
  };
  return (
    <AnalyticalTable
      data={props.data}
      columns={props.columns}
      renderRowSubComponent={renderRowSubComponent}
      subComponentsBehavior={AnalyticalTableSubComponentsBehavior.Expandable} //default value
    />
  );
};
```

</details>

