const States = { ...ValueState, ...IndicationColor };
export const InvertedObjectStatus: Story = {
  name: 'All States',
  render() {
    const renderStatuses = (interactive = false, inverted = false) => {
      return Object.values(States).map((state: ObjectStatusPropTypes['state']) => {
