        <UserMenuAccount
          avatarSrc="https://ui5.github.io/webcomponents/images/avatars/woman_avatar_3.png"
          titleText="Alaina Chevalier II"
          subtitleText="aliana.chevalier2@sap.com"
          description="Delivery Manager, SAP SE"
        ></UserMenuAccount>
